 y in zip(a, b))def recv_prompt(io, prompt=b&quot;(hex): &quot;, timeout=20): &quot;&quot;&quot;稳妥等待输入提示 &#x27;(hex): &#x27;，避免卡死&quot;&quot;&quot; io.recvuntil(prompt, timeout=timeout)def send_hex_get_H(io, raw: bytes) -&gt; bytes: &quot;&quot;&quot;发送 raw（以hex），并解析返回的 &#x27;H = ...&#x27; 为 bytes&quot;&quot;&quot; io.sendline(raw.hex().encode()) line = io.recvline(timeout=20) if not line: raise EOFError(&quot;对端在返回哈希前断开&quot;) s = line.decode(errors=&quot;ignore&quot;).strip() # 形如: H = f338fbc9e95d95f5a778be8902643b67 assert s.startswith(&quot;H = &quot;), f&quot;意外返回：&#123;s&#125;&quot; return bytes.fromhex(s[4:])def recv_round_result(io): &quot;&quot;&quot;发送完4条后读取回合结果行&quot;&quot;&quot; res = io.recvline(timeout=20) if not res: raise EOFError(&quot;对端在回合结果前断开&quot;) text = res.decode(errors=&quot;ignore&quot;).strip() print(text) # 可能还有空行 try: extra = io.recvline(timeout=0.3) if extra: print(extra.decode(errors=&quot;ignore&quot;), end=&quot;&quot;) except EOFError: pass return text# ===== 关键：每轮4次查询的确定性碰撞 =====def play_round(io, round_idx: int): # Step 1/2: 两条&quot;短消息&quot;学习 Δz1 A_short = b&quot;&quot; # 空串（单块） B_short = b&quot;\x00&quot; # 单字节（单块） # 1) A_short recv_prompt(io) # 等 &quot;MSG 1 (hex): &quot; H1 = send_hex_get_H(io, A_short) # 得到 H1 # 2) B_short recv_prompt(io) # 等 &quot;MSG 2 (hex): &quot; H2 = send_hex_get_H(io, B_short) # 得到 H2 # 计算对应的首块 B1, B2（我们本地可完全确定） B1 = pad_block_of_short_msg(A_short) # 16B B2 = pad_block_of_short_msg(B_short) # 16B # 拆 H 为 hi/lo（8B+8B） H1_hi, H1_lo = b2i(H1[:8]), b2i(H1[8:]) H2_hi, H2_lo = b2i(H2[:8]), b2i(H2[8:]) B1_lo, B2_lo = b2i(B1[8:]), b2i(B2[8:]) # Δz1 = (Δhi || Δlo)，其中 Δlo 需扣除 y_lo 差异 =&gt; ⊕(B1_lo ⊕ B2_lo) dz_hi = H1_hi ^ H2_hi dz_lo = (H1_lo ^ H2_lo) ^ (B1_lo ^ B2_lo) Dz = (dz_hi &lt;&lt; 64) | dz_lo Dz_bytes = i2b128(Dz) # 16B # Step 3/4: 两条&quot;长消息&quot;（32B）对齐第二块状态 + 共用PAD # 选择任意 16B 的 X，令 X&#x27; = X ⊕ Δz1 X = os.urandom(16) Xp = xor_bytes(X, Dz_bytes) # 构造两条32B消息：A_long = [B1 | X]，B_long = [B2 | X&#x27