P=&#123;ip0:04x&#125; OP=&#123;opcode:02x&#125;] &#123;msg&#125;
&quot; if hasattr(self, &quot;log_file&quot;) and self.log_file is not None: self.log_file.write(line) self.log_file.flush() else: print(line, end=&quot;&quot;) # 0x00: NOP if opcode == 0x00: log(&quot;NOP&quot;) return 1 # 0x01: JMP imm16 elif opcode == 0x01: imm = self.fetch_u16() # log(f&quot;JMP 0x&#123;imm:04x&#125;&quot;) self.ip = imm # 0x02: JNZ imm16 （推测：ZF==0 时跳转） elif opcode == 0x02: imm = self.fetch_u16() # log(f&quot;JNZ 0x&#123;imm:04x&#125;, ZF=&#123;self.zf&#125;&quot;) if not self.zf: self.ip = imm # 0x03: JZ imm16 （推测：ZF==1 时跳转） elif opcode == 0x03: imm = self.fetch_u16() # log(f&quot;JZ 0x&#123;imm:04x&#125;, ZF=&#123;self.zf&#125;&quot;) if self.zf: self.ip = imm # 0x11: 设置 base0（LOWORD(v92)） elif opcode == 0x11: imm = self.fetch_u16() # log(f&quot;SET base0 = 0x&#123;imm:04x&#125;&quot;) self.base0 = imm # 0x12: 设置 base1（WORD1(v92)） elif opcode == 0x12: imm = self.fetch_u16() # log(f&quot;SET base1 = 0x&#123;imm:04x&#125;&quot;) self.base1 = imm # 0x15: R[reg] = QWORD[mem[base0]] elif opcode == 0x15: reg = self.fetch_u8() if reg &gt;= 8: # raise IndexError(&quot;reg out of range in 0x15&quot;) return 0 val = self.read_u64(self.base0) # log(f&quot;LDQ R&#123;reg&#125; = [0x&#123;self.base0:04x&#125;] =&gt; 0x&#123;val:016x&#125;&quot;) self.regs[reg] = val # 0x16: R[reg] = imm64 elif opcode == 0x16: reg = self.fetch_u8() if reg &gt;= 8: return 0 # raise IndexError(&quot;reg out of range in 0x16&quot;) b = bytes(self.mem[self.ip:self.ip+8] + self.mem[:max(0, self.ip+8-MEM_SIZE)]) imm = struct.unpack_from(&quot;&lt;Q&quot;, b, 0)[0] self.ip = u16(self.ip + 8) self.regs[reg] = imm self.zf = (imm == 0) log(f&quot;LDI R&#123;reg&#125; = 0x&#123;imm:016x&#125;, ZF=&#123;self.zf&#125;&quot;) # 0x17: R[dst] = R[src] elif opcode == 0x17: dst = self.fetch_u8() src = self.fetch_u8() if dst &gt;= 8 or src &gt;= 8: return 0 # raise IndexError(&quot;reg out of range in 0x17&quot;) self.regs[dst] = self.regs[src] self.zf = (self.regs[dst] == 0) # log(f&quot;MOV