 input_ints=ints, debug_after_n=debug_after_n) out = vm.run(debug=debug) return out, vmmask64 = 0xFFFFFFFFFFFFFFFFmask32 = 0xFFFFFFFF# ---------- 基础函数: 与日志同构 ----------def loop_64bit(r0, r6): while True: r7 = r0 r7 = (r7 &amp; r6) &amp; mask64 r0 = (r0 ^ r6) &amp; mask64 if r7 == 0: break r7 = (r7 &lt;&lt; 1) &amp; mask64 r6 = r7 return r0def func_A_32bit(r_in): r6 = (r_in &gt;&gt; 8) &amp; mask32 r7 = (r_in &lt;&lt; 24) &amp; mask32 r6 = (r6 ^ r7) &amp; mask32 return r6def func_B_32bit(r0, r1): r6 = r1 while True: r7 = r0 r7 = (r7 &amp; r6) &amp; mask32 r0 = (r0 ^ r6) &amp; mask32 if r7 == 0: break r7 = (r7 &lt;&lt; 1) &amp; mask32 r6 = r7 r0 &amp;= mask32 return r0def func_C_32bit(r0, r2): return (r0 ^ r2) &amp; mask32def func_D_32bit(r_in): r6 = (r_in &lt;&lt; 3) &amp; mask32 r7 = (r_in &gt;&gt; 29) &amp; mask32 r6 = (r6 ^ r7) &amp; mask32 return r6def func_E_32bit(r0, r1): return (r1 ^ r0) &amp; mask32# ---------- 轮常量调度 R2[k] ----------def build_r2_schedule(r): &quot;&quot;&quot; 只跑 r2,r3,r4,r5 的“下半轮”，得到每一轮上半轮使用的 r2 常量。 &quot;&quot;&quot; r2 = r[0] r3 = r[1] r4 = r[2] r5 = r[3] R2 = [] for k in range(27): # 0..26 R2.append(r2) if k == 0x1a: # 最后一轮没有下半轮 continue r0_g_in = r3 r1_g_in = r2 r2_g_in = k r0_H_A = func_A_32bit(r0_g_in) r0_H_B = func_B_32bit(r0_H_A, r1_g_in) r0_H_C = func_C_32bit(r0_H_B, r2_g_in) r1_H_D = func_D_32bit(r1_g_in) r1_H_E = func_E_32bit(r0_H_C, r1_H_D) # 更新到下一轮 r2, r3, r4, r5 = r1_H_E, r4, r5, r0_H_C return R2# ---------- 上半轮显式逆 ----------def rol32(x, n): return ((x &lt;&lt; n) | (x &gt;&gt; (32 - n))) &amp; mask32def ror32(x, n): return ((x &gt;&gt; n) | (x &lt;&lt; (32 - n))) &amp; mask32def inv_upper_round(r0_next, r1_next, r2_k): &quot;&quot;&quot; 逆向一轮上半轮: 给定输出 (r0_next,r1_next) 和 r2_k, 求上一轮输入 (r0_prev,r1_prev) &quot;&quot;&quot; c0 = r0_next &amp; mask32 e1 = r1_next &amp; mask32 d1 = (e1 ^ c0) &amp; mask32 r1_prev = ror32(d1, 3) # 逆 D: ROL3 -&gt; ROR3 b0 = (c0 ^ r2_k) &amp; mask32 # 逆 C: XOR r2_k a0 = (b0 - r1_prev) &amp; mask32 # 逆 B