很乱，整理一下L3HCTF{wowthisisembedding} 量子双生影ntfs数据流隐写+ai二维码变换+双图合并 首先给出的二维码很明显可以用https://github.com/Tokeii0/LoveLy-QRCode-Scanner 这个项目进行扫描 给出的提示是 分析解压出的图片很明显和压缩包大小不符合，检索考察的是ntfs数据流隐写， 解压用ntfsstreamseditor这个工具提取一下得到另外一个图片，分析发现是两个图片进行了xor用现成工具或写脚本 123456789101112131415161718192021222324252627282930from PIL import Imagedef xor_images(img1_path, img2_path, output_path=&quot;xor_result.png&quot;): # 加载并转换为RGB格式 img1 = Image.open(img1_path).convert(&quot;RGB&quot;) img2 = Image.open(img2_path).convert(&quot;RGB&quot;) if img1.size != img2.size: raise ValueError(&quot;图片尺寸不一致，无法进行异或运算&quot;) w, h = img1.size result = Image.new(&quot;RGB&quot;, (w, h)) # 每像素逐位异或 for x in range(w): for y in range(h): r1, g1, b1 = img1.getpixel((x, y)) r2, g2, b2 = img2.getpixel((x, y)) result.putpixel((x, y), ( r1 ^ r2, g1 ^ g2, b1 ^ b2 )) result.save(output_path) print(f&quot;[+] 已保存异或图像为: &#123;output_path&#125;&quot;)# 示例用法if __name__ == &quot;__main__&quot;: xor_images(&quot;1.webp&quot;, &quot;2.webp&quot;, &quot;xor_result.png&quot;) 得到图片还是用项目解码 Please Sign In真签到题 ai梭哈点击就送哦内盖 丢给gpt让gpt生成脚本即可 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061import torchfrom torchvision import transformsfrom torchvision.models import shufflenet_v2_x1_0, ShuffleNet_V2_X1_0_Weightsfrom PIL import Imageimport jsonimport requestsimport osdef invert_embedding_to_image(embedding_path, output_path, steps=500, lr=0.1): # Load model model = shufflenet_v2_x1_0(weights=ShuffleNet_V2_X1_0_Weights.IMAGENET1K_V1) model.fc = torch.nn.Identity() model.eval() # Load target embedding with open(embedding_path, &#x27;r&#x27;) as f: target_emb = torch.tensor(json.load(f), dtype=torch.float32) # Initialize trainable image tensor (noise) img = torch.randn(1, 3, 224, 224, requires_grad=True) optimizer = torch.optim.Adam([img], lr=lr) for step in range(steps): optimizer.zero_grad() # Sigmoid to bound pixels between 0 and 1 clipped = img.sigmoid() emb = model(clipped)[0] loss = torch.nn.functional.mse_loss(emb, target_emb) loss.backward() optimizer.step() if step % 50 == 0: print(f&#x27;Step &#123;step&#125;, Loss &#123;loss.item():.6e&#125;&#x27;) # Convert to image and save result = (clipped.detach().squeeze().permute(1, 2, 0).cpu().numpy() * 255).astype(&#x27;uint8&#x27;) inv_image = Image.fromarray(result) inv_image.save(output_path) print(f&quot;Inverted image saved to &#x27;&#123;output_path&#125;&#x27;&quot;)def upload_and_print_response(image_path, server_url): if not os.path.exists(image_path): print(f&quot;File &#x27;&#123;image_path&#125;&#x27; not found.&quot;) return with open(image_path, &#x27;rb&#x27;) as f: files = &#123;&#x27;file&#x27;: f&#125; response = requests.post(server_url, files=files) try: print(&quot;Server response:&quot;, response.json()) except ValueError: print(&quot;Server response (text):&quot;, response.text)if __name__ == &quot;__main__&quot;: EMB_PATH = &#x27;embedding.json&#x27; OUT_IMG = &#x27;inverted_image.png&#x27; SIGNIN_URL = &#x27;http://1.95.8.146:50001/signin/&#x27; # Step 1: Invert embedding to image invert_embedding_to_image(EMB_PATH, OUT_IMG, steps=500, lr=0.1) # Step 2: Upload image and print the flag or failure upload_and_print_response(OUT_IMG, SIGNIN_URL) PaperBack给出了一条纸带上面全是点阵，看题目描述感觉像是拿纸带来保存数据，而且题目中提到了OllyDbg，通过关键词纸带和ollydbg可以搜到一个叫Paperback的东西：https://ollydbg.de/Paperbak/ ，下载这个软件扫描这条纸带可以扫描出一个很大的，但是内容空白的文件，放进Cyberchef转为hex可以看到： 只有20、09、0d、0a四种字符，而0d0a实际上就是
