 require(&#x27;uuid&#x27;);const check = require(&#x27;./check&#x27;); // 这里引入了 check 不知道是什么 但是是自定义的const app = express();const PORT = 8000;app.set(&#x27;views&#x27;, __dirname + &#x27;/views&#x27;);app.set(&#x27;view engine&#x27;, &#x27;ejs&#x27;);app.use(fileUpload(&#123; useTempFiles : true, tempFileDir : &#x27;/tmp/&#x27;, createParentPath : true&#125;));app.use(&#x27;/upload&#x27;,check()); // 这里调用了 check 应该是 在 ./check 的一个函数// 看到 这里用到了下面用到了 获取源码的方法app.get(&#x27;/source&#x27;, function(req, res) &#123; if (req.query.checkin)&#123; // 让 checkin == 1 res.sendfile(&#x27;/src/check.js&#x27;); // 这里我们可以猜测之前 check 的意思 应该就是这个文件 // 因此接下来我们要请求拿一下 check.js 但是不急 我们接着看 &#125; res.sendfile(&#x27;/src/server.js&#x27;); // 就是我们当前的文件&#125;);// 我们的根目录 生成了一个 formidapp.get(&#x27;/&#x27;, function(req, res) &#123; var formid = &quot;form-&quot; + uuidv4(); res.render(&#x27;index&#x27;, &#123;formid : formid&#125; );&#125;);// 这里是上传点 一般这里大家都会警觉app.post(&#x27;/upload&#x27;, function(req, res) &#123; let sampleFile; let uploadPath; let userdir; let userfile; // 样本文件 获取 用的是 req.query.formid 注意可以是数字 不一定是 字符串 sampleFile = req.files[req.query.formid]; // 这里处理 文件 hash 用的 md5 分别计算了 文件 hash 和 上传者的地址 // node 会获取 ::ffff:&#123;ipv4&#125; 作为你的 ip 地址 userdir = md5(md5(req.socket.remoteAddress) + sampleFile.md5); userfile = sampleFile.name.toString(); // 文件名就是 name 字段 不是 filename 字段 正常情况是 你的 formid if(userfile.includes(&#x27;/&#x27;)||userfile.includes(&#x27;..&#x27;))&#123; return res.status(500).send(&quot;Invalid file name&quot;); &#125; // 上传到的地址 注意这里是绝对地址 uploadPath = &#x27;/uploads/&#x27; + userdir + &#x27;/&#x27; + userfile; sampleFile.mv(uploadPath, function(err) &#123; if (err) &#123; return res.status(500).send(err); &#125; // 这里提到了第二个端口 // 这里也说明了 上传的文件你可以在这个地址访问到 // 文件上传 getshell 基本都要用到 这个地址访问 然后让服务器执行 res.send(&#x27;File uploaded to http://47.243.75.225:31338/&#x27; + userdir + &#x27;/&#x27; + userfile); &#125;);&#125;);app.listen(PORT, function() &#123; console.log(&#x27;Express server listening on port &#x27;, PORT);&#125;); check 审计接下来 看看我们的 check.js 1234567891011121314151617181920212223242526$ curl 127.0.0.1:31337/source?checkin=1 | tee check.jsmodule.exports = () =&gt; &#123; return (req, res, next) =&gt; &#123; if ( !req.query.formid || !req.files || Object.keys(req.files).length === 0) &#123; // 确认你有上传 res.status(400).send(&#x27;Something error.&#x27;); return; &#125; // 对每个文件的 key 进行检查 (其实这里有个例外 __proto__ 是个例外) Object.keys(req.files).forEach(function(key)&#123; var filename = req.files[key].name.toLowerCase(); var position = filename.lastIndexOf(&#x27;.&#x27;); if (position == -1) &#123; return next(); &#125; // 如果没有 . 就下一个文件 这里其实也有个 bypass 点位 也就是上传两个文件 用第一个 无后缀的安全文件 bypass var ext = filename.substr(position); var allowexts = [&#x27;.jpg&#x27;,&#x27;.png&#x27;,&#x27;.jpeg&#x27;,&#x27;.html&#x27;,&#x27;.js&#x27;,&#x27;.xhtml&#x27;,&#x27;.txt&#x27;,&#x27;.realworld&#x27;]; if ( !allowexts.includes(ext) )&#123; // 确认安全文件名后缀 res.status(400).send(&#x27;Something error.&#x27;); return; &#125; return next(); // 所有检查完毕后 就 返回下一个文件 &#125;); &#125;; &#125;; 看一眼 31338 端口这里可以看一眼 31338 端口 然后 curl 一下 1234567891011121314151617181920$ curl 127.0.0.1:31338 -v* Trying 127.0.0.1:31338...* Connected to 127.0.0.1 (127.0.0.1) port 31338 (#0)&gt; GET / HTTP/1.1&gt; Host: 127.0.0.1:31338&gt; User-Agent: curl/7.81.0&gt; Accept: */*&gt; * Mark bundle as not supporting multiuse&lt; HTTP/1.1 200 OK&lt; Date: Thu, 27 Jan 2022 15:48:27 GMT&lt; Server: Apache/2.4.29 (Ubuntu)&lt; Last-Modified: Thu, 20 Jan 2022 09:18:15 GMT&lt; ETag: &quot;31-5d5fffb6aa3c0&quot;&lt; Accept-Ranges: bytes&lt; Content-Length: 49&lt; Content-Type: text/html&lt; * Connection #0 to host 127.0.0.1 left intactWelcome to my CDN! Execute /readflag to get flag. 这里就是个 普通 apache 而上面的两个 则是 Express 思路和利用既然上传这里 有问题 那么就试试上传 看看能不能弄到点什么 很显然 getshell 的任何 php pl 脚本代码都是不能成功利用的 就是个 简简单单的 纯纯的 Apache 服务器 第一部分既然是 apache 目标, 自然 .htaccess apache.conf 这种配置文件 很显然就变成了我们的目标 你或许以为直接 cgi script 进行一把梭就完事了 很显然 这里服务器 默认是没有开