1].length() == 4) &amp;&amp; (boost::all(res[1],boost::is_from_range(&#39;a&#39;,&#39;g&#39;) || boost::is_from_range(&#39;A&#39;, &#39;G&#39;)))) 长度是4，每个字符都是[A-Ga-g] 经过boost::to_upper要求和原string相同，这表明输入的4个字符都是大写字母 限制范围在[A-G]了 要求4个字符的数值递增，步长为2, 那么只能ACEG 也就是第二个的输入 第三个，res[2] 通过boost::all(res[2],boost::is_digit())判断要求都是数字，小于10位，转成int，记作sum 要求(sum % 2 == 0) &amp;&amp; (func(sum) == -1412590079) &amp;&amp; (func2(sum) == 305392417) 如果不加第一个%2&#x3D;&#x3D;0的条件，会有三个结果31415925 31415926 31415927 这样下来只有一个结果31415926 int范围内只有这一个符合要求 也就是第三个输入 那么输入就形如11111suctf-ACEG-31415926 输出为 suctf{ACEG31415926}You win! Akira Homework程序是一个Windows下的程序，开始的时候会要求输入密码。 1234[+]======================[+][+] Akira&#x27;s Homework 2nd [+][+]======================[+][=] My passwords is: 分析可以直接使用ida对程序逻辑进行分析。从程序的某些迹象中可以发现，大部分的字符串似乎都被加密了。并且当用调试器连接的时候，程序会直接强行关闭，程序运行时间长也会自行关闭。解决方案可以是Patch程序的反调试逻辑等。这边提出的解决方案是使用dmp的方式结合着分析程序，这样能够提高解答的速度。通过dmp的方式，能够找到程序的第一个输入点: 1234for( i=0; i &lt; 0x6c; ++1) Str[i] ^= byte_7ff766972AE0[0]puts(Str)sub_7FF76959C80(&quot;%18s&quot;, &amp;v4, 19i64); 直接逆向这一段，能够找到程序当前使用的密钥为: 1Akira_aut0_ch3ss_! 输入这段逻辑，此时会发现程序提示 1Have no sign! 返回程序检查，会发现有一个check逻辑int sub_7FF682FC93B0()，里面检查了一个叫做Alternate Data Streams的东西，并且将这个数据做了一次md5签名检查，通过查询可以查到签名内容为 1Overwatch 给exe加上Alertable Data Streaming之后，就能够通过检测。在刚刚的提示框后，会要求输入第二次答案，这个答案才是flag: 1Now check the sign: dmp下程序后，会发现还有一个dll也藏在进程中。将DLL取出逆向，观测可知，其尝试打开了一个ShareMemory，并且读出了里面的内容，传入了函数sub_180011136。所以这里猜测，在这个程序运行的过程中，在主线程中必定也存在一个对称操作。于是检查原先的exe，找到调用MapViewOfFile的周围 1234.text:000000014000771F mov [rsp+0B8h+Src], 7Ch.text:0000000140007727 mov [rsp+0B8h+var_2F], 45h.text:000000014000772F mov [rsp+0B8h+var_2E], 38h... 如果使用了工具分析这个dmp下来的dll，会发现其中有一个类似AES算法的东西，也就是这个sub_180011136函数的。最终可以解得flag为: 1flag&#123;Ak1rAWin!&#125; 吐槽：题目没有设计好，导致DLL的解密逻辑好像很容易被找出来，结果很多师傅似乎拿到第一个key之后直接就解开了dll。。。本意是想让大家了解一下Windows下的ADS作为签名的用途的。果然还是出题人太菜了 SignIn使用了gmp大数库实现了一个简单的rsa,题目中只有N e,由于N不是很大,可以直接分解,得到p q,然后生成d,即可解出flag babyunic先放上源码 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778#include &lt;unicorn/unicorn.h&gt;#include &lt;string.h&gt;#include &lt;math.h&gt;#include &lt;sys/ptrace.h&gt;#include &lt;stdio.h&gt;#define ADDRESS 0x400000#define STACK 0x10000000#define SZ 0x200000int flagenc[50] =&#123; 0x94ffffff,0x38ffffff,0x26010000,0x28ffffff,0x10fcffff,0x94020000,0x9efcffff,0xea060000,0xdc000000,0x6000000,0xcffffff,0xf6fdffff,0x82faffff,0xd0fcffff,0x82010000,0xde030000,0x4e010000,0xb2020000,0xd8f8ffff,0x74010000,0xa6faffff,0xd4f9ffff,0xc2010000,0x7cf9ffff,0x5a030000,0x46010000,0x3cffffff,0x14faffff,0xce010000,0xdc070000,0x48fdffff,0x98000000,0x5e080000,0xb0fdffff,0xbcffffff,0x6e030000,0x4effffff,0x36f8ffff,0xc0050000,0xae060000,0x94060000,0x22000000&#125;;int calc(char * input,char * output,char * filename)&#123; uc_engine *uc; FILE * file = fopen(filename,&quot;rb&quot;); unsigned char * opc = malloc(0x7100); fread(opc,1,0x7100,file); int sp = STACK + SZ - 0x40; int fp = STACK + SZ - 0x40; int a0 = STACK + SZ - 0x500; int a1 = STACK + SZ - 0x600; uc_open(UC_ARCH_MIPS, UC_MODE_MIPS32 + UC_MODE_BIG_ENDIAN, &amp;uc); uc_mem_map(uc, ADDRESS, SZ, UC_PROT_ALL); uc_mem_map(uc, STACK, SZ, UC_PROT_ALL); uc_mem_write(uc , a0,input,strlen(input)); uc_mem_write(uc, ADDRESS,opc, 0x7100); uc_reg_write(uc, UC_MIPS_REG_SP, &amp;sp); uc_reg_write(uc, UC_MIPS_REG_FP, &amp;fp); uc_reg_write(uc, UC_MIPS_REG_A1, &amp;a1); uc_reg_write(uc, UC_MIPS_REG_A0, &amp;a0); uc_emu_start(uc, ADDRESS, ADDRESS + 0x7070 - 4, 0, 0); uc_mem_read(uc, STACK + SZ - 0x600,output,200); uc_close(uc); fclose(file);&#125;void __attribute__((constructor)) check()&#123; if(ptrace(0,0,0,0)==-1) exit(0);&#125;int main(int argc,char *argv[])&#123; if(argc == 2) &#123; puts(&quot;SUCTF 2019&quot;); printf(&quot;input your flag:&quot;); char * output = malloc(0x200); char * input = malloc(0x200); scanf(&quot;%50s&quot;,input); calc(input,output,argv[1]); if(!memcmp(output,flagenc,168)) &#123; puts(&quot;congratuation!&quot;); &#125; else &#123; puts(&quot;fail!&quot;); &#125; &#125; else &#123; puts(&quot;no input files&quot;); &#125;&#125; 出这个题的原因是最近在看各种奇奇怪怪的fuzz,8月初平安银河实验室推了一个基于libfuzzer和unicorn模拟执行的fuzzing工具,是利用了unicorn来进行模拟执行,然后利用libfuzzer提供的__libfuzzer_extra_counters接收覆盖率,进行数据的变异等操作 出题的时候使用的是mips-linux-gnu-gcc在ubuntu1604下编译出的一个大端序的mips32,这里编写了一个类似void func(char * in,char * out)的函数,因为unicorn对于原生函数的调用的支持不是很好,所以这个函数里面没有用到库函数以及系统调用 函数里设置了一个位运算,以及一个42元方程,函数运行后会返回方程的值,这里的值也是大端序的,然后进行比较.题目无混淆无花,模拟执行的算法也是很基础的,事先也给了依赖库,目的是想让各位师傅们了解一下这个神奇的模拟引擎(希望我不是最后一个知道的),在出题的过程中也发现了一个问题就是z3对于这个42元方程的速度异常的慢. 这个场景下的unicorn感觉可以用在iot的fuzz上,不过要注意的是这东西毕竟是模拟执行,所以效率不是很高 解题思路就是学一波unicorn,然后根据uc_open函数参数的值找到要模拟字节码的架构,然后使用对应的反编译工具对func文件进行逆向,dump出大端序的res,用求解器算出flag Crypto 详情见 Writeup.html。
